# ReAct agent implementation
import json
from openai import OpenAI

client = OpenAI()

class ReActAgent:
    """Reasoning + Acting agent with tool use"""

    def __init__(self, tools, system_prompt, max_steps=15):
        self.tools = tools  # list of callable tool dicts
        self.system_prompt = system_prompt
        self.max_steps = max_steps

    def run(self, query):
        messages = [
            {"role": "system", "content": self.system_prompt},
            {"role": "user", "content": query}
        ]

        for step in range(self.max_steps):
            response = client.chat.completions.create(
                model="gpt-4",
                messages=messages,
                temperature=0.2
            )
            content = response.choices[0].message.content

            # Check if agent provides final answer
            if "FINAL ANSWER:" in content:
                return content.split("FINAL ANSWER:")[-1].strip()

            # Parse tool call: ACTION: tool_name | input
            if "ACTION:" in content:
                action_line = content.split("ACTION:")[-1].strip()
                tool_name, tool_input = action_line.split("|", 1)
                tool_input = tool_input.strip()

                # Execute tool
                if tool_name in self.tools:
                    try:
                        observation = self.tools[tool_name](tool_input)
                    except Exception as e:
                        observation = f"Error: {e}"
                else:
                    observation = f"Unknown tool: {tool_name}"

                # Add to conversation history
                messages.append({"role": "assistant", "content": content})
                messages.append({
                    "role": "user",
                    "content": f"OBSERVATION: {observation}\nContinue reasoning."
                })
            else:
                # No action, no final answer — ask for clarification
                messages.append({"role": "assistant", "content": content})
                messages.append({
                    "role": "user",
                    "content": "Please provide either an ACTION or FINAL ANSWER."
                })

        return "Max steps reached without final answer."

